mapper.select:
SELECT t.team_id, t.name, t.description, t.creator_id, t.max_members, t.status, t.created_at, t.updated_at, u.username AS creator_name, COUNT(tm.user_id) AS current_members, GROUP_CONCAT(DISTINCT s.skill_name ORDER BY s.skill_name SEPARATOR ',') AS required_skills FROM teams t LEFT JOIN users u ON t.creator_id = u.user_id LEFT JOIN team_members tm ON t.team_id = tm.team_id LEFT JOIN team_required_skills trs ON t.team_id = trs.team_id LEFT JOIN skills s ON trs.skill_id = s.skill_id
AND t.status = #{status}
AND t.name LIKE CONCAT('%', #{keyword}, '%')
AND EXISTS ( SELECT 1 FROM team_required_skills trs2 WHERE trs2.team_id = t.team_id AND trs2.skill_id = #{skillId} )
GROUP BY t.team_id, t.name, t.description, t.creator_id, t.max_members, t.status, t.created_at, t.updated_at, u.username
HAVING COUNT(tm.user_id) >= #{minMembers}
AND COUNT(tm.user_id) <= #{maxMembers}
HAVING COUNT(tm.user_id) <= #{maxMembers}
ORDER BY t.created_at DESC
